			output << ( index ? "," : "" )
				   << "{\"face\":" << value.face
				   << ",\"mip\":" << value.mip
				   << ",\"width\":" << value.width
				   << ",\"height\":" << value.height
				   << ",\"format\":" << static_cast<uint32_t>( value.format )
				   << ",\"hash\":";
